import elasticapm
from flask import Flask, request, jsonify
import sqlite3

# Initialize the Flask application
app = Flask(__name__)

# Configure Elastic APM
elasticapm.instrument()
app.config['ELASTIC_APM'] = {
    'SERVICE_NAME': 'my-python-app',
    'SECRET_TOKEN': 'your-secret-token',
    'SERVER_URL': 'http://localhost:8200',
    'CAPTURE_BODY': 'all',
    'CAPTURE_HEADERS': True,
    'TRANSACTIONS_IGNORE_PATTERNS': ['^OPTIONS '],
    'STACK_TRACE_LIMIT': 50,
}

# Initialize the APM client
apm = elasticapm.Client(app.config['ELASTIC_APM'])
elasticapm.instrument()

@app.route('/data', methods=['GET', 'POST'])
def data():
    if request.method == 'POST':
        content = request.json
        # Securely handle SQL queries
        with sqlite3.connect('example.db') as conn:
            cursor = conn.cursor()
            cursor.execute("INSERT INTO data (name, value) VALUES (?, ?)", (content['name'], content['value']))
            conn.commit()
        return jsonify({'status': 'success'}), 201

    elif request.method == 'GET':
        with sqlite3.connect('example.db') as conn:
            cursor = conn.cursor()
            cursor.execute("SELECT * FROM data")
            rows = cursor.fetchall()
        return jsonify(rows)

# Add APM middleware
@app.before_request
def before_request():
    elasticapm.set_context(lambda: {'request': request})

@app.after_request
def after_request(response):
    elasticapm.set_context(lambda: {'response': response})
    return response

if __name__ == '__main__':
    app.run(debug=True)